<!DOCTYPE html>
<html>
<head>
  <title>Maze Game</title>
  <style>
    body {
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    #maze {
      border: 1px solid black;
      margin: 20px;
    }

    canvas {
      background-color: #eee;
    }

    #controls {
      margin-top: 20px;
      text-align: center;
    }
  </style>
</head>
<body>
  <h1>Maze Game</h1>
  <div id="maze">
    <canvas id="myCanvas"></canvas>
  </div>
  <div id="controls">
    <p>Completed: <span id="completed">0</span></p>
    <p>Timer: <span id="timer">0</span></p>
    <button id="reset">Reset</button>
  </div>

  <script>
    const canvas = document.getElementById('myCanvas');
    const ctx = canvas.getContext('2d');
    const completedSpan = document.getElementById('completed');
    const timerSpan = document.getElementById('timer');
    const resetButton = document.getElementById('reset');

    const size = { rows: 25, cols: 25 }; // Maze dimensions
    const numBots = 24;
    let elapsed = 0;
    let gameRunning = true;

    // Bot data
    let bots = [];
    for (let i = 0; i < numBots; i++) {
      bots.push({ path: [], deadEnds: [], finishTick: null });
    }

    const exit = { r: size.rows - 1, c: size.cols - 1 };

    // Maze generation (simplified for this example)
    function generateMaze() {
      let maze = [];
      for (let r = 0; r < size.rows; r++) {
        maze[r] = new Array(size.cols).fill(true); // Initialize all walls
      }

      // Simple random carving - not a perfect maze, but functional for testing
      for (let r = 1; r < size.rows - 1; r++) {
        for (let c = 1; c < size.cols - 1; c++) {
          if (Math.random() > 0.7) { // Adjust probability for density
            maze[r][c] = false;
          }
        }
      }

      // Ensure entrance and exit are open
      maze[0][1] = false;
      maze[size.rows - 1][size.cols - 2] = false;

      return maze;
    }


    // Bot movement logic (Tremaux/DFS)
    function moveBot(bot, maze) {
      let currentCell = bots[bot].path[bots[bot].path.length - 1];
      let directions = ['e', 's', 'w', 'n'];
      directions = directions.sort(() => Math.random() - 0.5); // Random direction order

      for (const dir of directions) {
        let newRow = currentCell.r;
        let newCol = currentCell.c;

        switch (dir) {
          case 'e': newCol++; break;
          case 's': newRow++; break;
          case 'w': newCol--; break;
          case 'n': newRow--; break;
        }

        if (newRow >= 0 && newRow < size.rows && newCol >= 0 && newCol < size.cols) {
          if (!maze[newRow][newCol]) {
            bot.path.push({ r: newRow, c: newCol });
            return;
          }
        }
      }

      // Backtrack if no valid moves
      if (bot.path.length > 1) {
        bot.path.pop();
      }
    }


    function tick() {
      if (!gameRunning) return;

      elapsed++;
      timerSpan.textContent = elapsed;

      for (let i = 0; i < numBots; i++) {
        if (bots[i].finishTick === null) {
          moveBot(i, maze);
        }
      }

      // Check if all bots have reached the exit
      let allFinished = true;
      for (let i = 0; i < numBots; i++) {
        if (bots[i].finishTick === null) {
          allFinished = false;
          break;
        }
      }

      if (allFinished) {
        completedSpan.textContent = numBots;
        gameRunning = false;
      }

      // Render the maze and bots
      renderMaze(maze);
      renderBots(bots);
    }


    function renderMaze(maze) {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      for (let r = 0; r < size.rows; r++) {
        for (let c = 0; c < size.cols; c++) {
          if (maze[r][c]) {
            ctx.fillStyle = 'black';
            ctx.fillRect(c * 20, r * 20, 20, 20);
          } else {
            ctx.fillStyle = 'white';
            ctx.fillRect(c * 20, r * 20, 20, 20);
          }
        }
      }
    }

    function renderBots(bots) {
      for (let i = 0; i < numBots; i++) {
        if (bots[i].finishTick !== null) {
          ctx.fillStyle = 'green'; // Exit color
        } else {
          ctx.fillStyle = 'blue';
        }

        const botPos = bots[i].path[bots[i].path.length - 1];
        ctx.beginPath();
        ctx.arc(botPos.c * 20 + 10, botPos.r * 20 + 10, 5, 0, Math.PI * 2);
        ctx.fill();
      }
    }


    resetButton.addEventListener('click', () => {
      gameRunning = true;
      elapsed = 0;
      completedSpan.textContent = 0;
      timerSpan.textContent = 0;
      bots = [];
      for (let i = 0; i < numBots; i++) {
        bots.push({ path: [], deadEnds: [], finishTick: null });
      }
      maze = generateMaze();
    });


    // Initial maze generation and bot placement
    const maze = generateMaze();
    const spawnPos = { r: 0, c: 1 };
    for (let i = 0; i < numBots; i++) {
      bots[i].path.push(spawnPos);
      bots[i].deadEnds = [];
      bots[i].finishTick = null;
    }

    // Start the game loop
    function gameLoop() {
      tick();
      requestAnimationFrame(gameLoop);
    }

    gameLoop();
  </script>
</body>
</html>
